entry.content:
Beautifulsoup 简单爬取笔趣阁的一本小说（从自己的简书的文章拷贝过来）我写这个代码的主要目的是针对一个关于上面的题目的博文进行修改，其实，这个博文讲的不错，但是由于网站更新了，他的代码有些地方是不灵的。所以我就修改了一些。 这个博文 修改后的代码：(解释见注释) 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051from bs4 import BeautifulSoupimport requests, sysclass downloader(object): def __init__(self): self.server = &quot;http://www.biqukan.com/&quot; self.target = &quot;http://www.biqukan.com/1_1094/&quot; self.name = [] self.url = [] self.nums = 0 def get_download_url(self): req = requests.get(url = self.target) # 获取网页的内容。 req.encoding = req.apparent_encoding # 为了防止出现乱码，如果没有加这个的话，会出现乱码的。 html = req.text div_soup = BeautifulSoup(html, &quot;lxml&quot;) # 解析，注意要加上&apos;lxml&apos; div = div_soup.find_all(&apos;div&apos;, class_ = &apos;listmain&apos;) # div的类型是bs4.element.ResultSet，是一个列表，不过在这个列表中，它的长度仅为1。 # 所以用div[0]读取内容。 a_soup = BeautifulSoup(str(div[0]), &quot;lxml&quot;) # Beautifulsoup()里面传入的是str类型。 a = a_soup.find_all(&apos;a&apos;) self.nums = len(a[16:]) for i in a[16:]: self.name.append(i.string) self.url.append(self.server + i.get(&apos;href&apos;)) # i.get(&apos;href&apos;)是str类型。 def get_content(self, target): req = requests.get(target) req.encoding = req.apparent_encoding # 这个也是为了防止出现乱码的。 html = req.text soup = BeautifulSoup(html, &apos;lxml&apos;) texts = soup.find_all(&apos;div&apos;, class_ = &apos;showtxt&apos;) texts = texts[0].text.replace(&apos; &apos;,&apos;
&apos;).replace(&apos;\xa0&apos;*8,&apos; &apos;) # 这个我不懂为什么为什么要加这个。反正只要加了这个， # 就会输出需要的内容。 return texts def writer(self, name, path, text): with open(path, &apos;a&apos;, encoding= &apos;utf-8&apos;) as f: f.write(name + &apos;
&apos;) f.writelines(text) f.write(&apos;

&apos;)if __name__ == &apos;__main__&apos;: dl = downloader() dl.get_download_url() print(&quot;开始下载：&quot;) for i in range(dl.nums): dl.writer(dl.name[i], &apos;一念永恒.txt&apos;, dl.get_content(dl.url[i])) # print(&quot; 已下载:%.3f%%&quot; % float(i/dl.nums) + &apos;&apos;) sys.stdout.write(&quot;&quot; + &quot;已下载:%.2f%%&quot; % float(100.0 * i/dl.nums)) # 在一行动态输出，下面的一行也必须要写。 sys.stdout.flush() print(&quot;下载结束&quot;) 其中，关于在一行动态输出的博文可以见：https://blog.csdn.net/weixin_33736048/article/details/86263346
